<template><main class="container py-5 news-detail"><div v-if="error" class="alert alert-danger">{{ error }}</div><article v-else-if="news"><span class="eyebrow">TIN TỨC CARSTORE</span><h1>{{ news.title }}</h1><p class="meta">{{ formatDate(news.createdAt) }} · {{ news.author }}</p><img v-if="news.thumbnail" :src="carImageUrl(news.thumbnail)" :alt="news.title"><p class="summary">{{ news.summary }}</p><div class="content">{{ news.content }}</div></article><div v-else class="text-center">Đang tải...</div></main></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute}from'vue-router';import{newsApi,carImageUrl}from'../api';const route=useRoute(),news=ref(null),error=ref('');const formatDate=v=>v?new Date(v).toLocaleDateString('vi-VN'):'';onMounted(async()=>{try{const{data}=await newsApi.getBySlug(route.params.slug);news.value=data.data}catch(e){error.value=e.response?.data?.message||'Không thể tải tin tức'}})</script>
<style scoped>.news-detail{max-width:900px}.eyebrow{color:#b91c1c;font-weight:800}.news-detail h1{font-weight:900;margin:10px 0}.meta{color:#6b7280}.news-detail img{width:100%;max-height:480px;object-fit:cover;border-radius:14px;margin:20px 0}.summary{font-size:1.15rem;font-weight:700}.content{white-space:pre-wrap;line-height:1.8}</style>
